defmodule MyAppWeb.PostLive.Show do
  use MyAppWeb, :live_view

  def mount(%{"id" => id}, _session, socket) do
    post = get_post(id)
    sanitized_content = HtmlSanitizeEx.basic_html(post.content)
    
    {:ok, assign(socket, post: %{post | content: sanitized_content})}
  end

  def render(assigns) do
    ~H"""
    <div class="post-container">
      <h1><%= @post.title %></h1>
      <div class="post-meta">
        <span>By <%= @post.author %></span>
        <span><%= @post.published_at %></span>
      </div>
      <div class="post-content">
        <%= raw @post.content %>
      </div>
    </div>
    """
  end

  defp get_post(id) do
    %{
      id: id,
      title: "Sample Post",
      author: "John Doe",
      published_at: "2024-01-01",
      content: "<p>User content here</p>"
    }
  end
end